class Solution {
public:
    string tree2str(TreeNode* r) {
        if(!r) return "";
        string s=to_string(r->val);
        if(!r->left&&!r->right) return s;
        if(!r->left) return s+"()("+tree2str(r->right)+")";
        s+="("+tree2str(r->left)+")";
        if(r->right) s+="("+tree2str(r->right)+")";
        else s+="()";
        return s;
    }
};

